+package robot
+
+import (
+	"testing"
+
+	"github.com/Dicklesworthstone/ntm/internal/agent"
+)
+
+func TestDefaultIsWorkingOptions(t *testing.T) {
+	opts := DefaultIsWorkingOptions()
+
+	if opts.LinesCaptured != 100 {
+		t.Errorf("expected LinesCaptured=100, got %d", opts.LinesCaptured)
+	}
+	if opts.Verbose {
+		t.Error("expected Verbose=false")
+	}
+	if opts.Session != "" {
+		t.Errorf("expected empty Session, got %q", opts.Session)
+	}
+	if len(opts.Panes) != 0 {
+		t.Errorf("expected empty Panes, got %v", opts.Panes)
+	}
+}
+
+func TestParsePanesArg(t *testing.T) {
+	tests := []struct {
+		name      string
+		input     string
+		expected  []int
+		expectErr bool
+	}{
+		{
+			name:     "empty string returns empty slice",
+			input:    "",
+			expected: []int{},
+		},
+		{
+			name:     "all keyword returns empty slice",
+			input:    "all",
+			expected: []int{},
+		},
+		{
+			name:     "ALL uppercase returns empty slice",
+			input:    "ALL",
+			expected: []int{},
+		},
+		{
+			name:     "single pane",
+			input:    "2",
+			expected: []int{2},
+		},
+		{
+			name:     "multiple panes",
+			input:    "1,2,3",
+			expected: []int{1, 2, 3},
+		},
+		{
+			name:     "panes with spaces",
+			input:    "1, 2, 3",
+			expected: []int{1, 2, 3},
+		},
+		{
+			name:     "pane zero is valid",
+			input:    "0",
+			expected: []int{0},
+		},
+		{
+			name:      "negative pane is invalid",
+			input:     "-1",
+			expectErr: true,
+		},
+		{
+			name:      "non-numeric is invalid",
+			input:     "abc",
+			expectErr: true,
+		},
+		{
+			name:      "mixed valid and invalid",
+			input:     "1,abc,3",
+			expectErr: true,
+		},
+		{
+			name:     "trailing comma",
+			input:    "1,2,",
+			expected: []int{1, 2},
+		},
+		{
+			name:     "leading comma",
+			input:    ",1,2",
+			expected: []int{1, 2},
+		},
+	}
+
+	for _, tc := range tests {
+		t.Run(tc.name, func(t *testing.T) {
+			result, err := ParsePanesArg(tc.input)
+
+			if tc.expectErr {
+				if err == nil {
+					t.Errorf("expected error for input %q, got nil", tc.input)
+				}
+				return
+			}
+
+			if err != nil {
+				t.Errorf("unexpected error for input %q: %v", tc.input, err)
+				return
+			}
+
+			if len(result) != len(tc.expected) {
+				t.Errorf("expected %v, got %v", tc.expected, result)
+				return
+			}
+
+			for i, v := range tc.expected {
+				if result[i] != v {
+					t.Errorf("at index %d: expected %d, got %d", i, v, result[i])
+				}
+			}
+		})
+	}
+}
+
+func TestGetRecommendationReason(t *testing.T) {
+	tests := []struct {
+		name     string
+		state    *agent.AgentState
+		contains string // substring that should be in the reason
+	}{
+		{
+			name: "working agent",
+			state: &agent.AgentState{
+				IsWorking: true,
+			},
+			contains: "actively producing",
+		},
+		{
+			name: "idle agent",
+			state: &agent.AgentState{
+				IsIdle: true,
+			},
+			contains: "idle",
+		},
+		{
+			name: "rate limited agent",
